    challenge_id = ma.fields.Int(required=True)
    answer = ma.fields.Str(required=True)


class VerifyResponseSchema(ma.Schema):
    valid = ma.fields.Bool()
    token = ma.fields.Str(load_default=None, dump_default=None)
