        pagination = get_ledger(
            user_id=user_id,
            currency=currency,
            date_from=date_from,
            date_to=date_to,
            page=page,
            per_page=per_page,
        )

        return jsonify({
            "items": [_ledger_entry_dict(e) for e in pagination.items],
