    @require_role("admin", "moderator")
    def delete(self, id, user_id):
        from app.models.asset import DownloadGrant
        from app.extensions import db

        grant = DownloadGrant.query.filter_by(asset_id=id, user_id=user_id).first()
        if grant is None:
